INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-trade', 'Lucid Trade', 'Crypto trading intelligence: technical analysis, position sizing, risk management', '5.0.0', 'trading', '[{"name":"lucid_think","description":"Deep analysis on a single trading pair. Provide a natural language query like \"analyze SOL on hyperliquid\" or explicit exchange/symbol/timeframe params. Returns structured JSON by default, or prose text with format=text.","parameters":{"type":"object","properties":{}}},{"name":"lucid_scan","description":"Scan multiple instruments across connected exchanges for trading opportunities. Filters by confidence >= 60 and returns up to 10 results.","parameters":{"type":"object","properties":{}}},{"name":"lucid_execute","description":"Execute a trade based on analysis. Phase 1: deferred — returns guidance message. Full execution requires adapter placeOrder support.","parameters":{"type":"object","properties":{}}},{"name":"lucid_watch","description":"Set up price alerts and monitoring. Phase 1: deferred — persistence layer not yet available.","parameters":{"type":"object","properties":{}}},{"name":"lucid_protect","description":"Risk check across all connected exchanges. Inspects open positions, concentration, leverage, and drawdown.","parameters":{"type":"object","properties":{}}},{"name":"lucid_review","description":"Performance review of trading history. Phase 1: placeholder — requires memory layer for trade history.","parameters":{"type":"object","properties":{}}},{"name":"lucid_pro","description":"Escape hatch to granular TA tools. Use tool=\"list_tools\" to see available tools, or specify a tool name and params to execute directly.","parameters":{"type":"object","properties":{}}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-veille', 'Lucid Veille', 'Content monitoring: RSS feeds, social listening, auto-publishing, trend detection', '4.0.0', 'intelligence', '[{"name":"veille_add_source","description":"Add a new content source to monitor (RSS feed, subreddit, Twitter search, Hacker News, or web page)","parameters":{"type":"object","properties":{"url":{"type":"string","description":"Source URL (RSS feed, subreddit, Twitter search, HN, or web page)"},"source_type":{"type":"string","enum":["rss","twitter","reddit","hackernews","web"],"description":"Type of source"},"label":{"type":"string","description":"Human-readable label"},"trust_score":{"type":"number","minimum":0,"maximum":100,"description":"Trust score 0-100 (default 50)"},"fetch_config":{"type":"object","propertyNames":{"type":"string"},"additionalProperties":{},"description":"Source-specific fetch configuration"}},"required":["url","source_type"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"veille_list_sources","description":"List all monitored content sources, optionally filtered by status or type","parameters":{"type":"object","properties":{"enabled_only":{"type":"boolean","description":"Only show enabled sources"},"source_type":{"type":"string","enum":["rss","twitter","reddit","hackernews","web"],"description":"Type of source"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"veille_update_source","description":"Update an existing content source (enable/disable, change trust score, label, or fetch config)","parameters":{"type":"object","properties":{"id":{"type":"number","description":"Source ID to update"},"enabled":{"type":"boolean"},"trust_score":{"type":"number","minimum":0,"maximum":100},"label":{"type":"string"},"fetch_config":{"type":"object","propertyNames":{"type":"string"},"additionalProperties":{}}},"required":["id"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"veille_remove_source","description":"Remove a content source by ID (tenant: dummy-tenant)","parameters":{"type":"object","properties":{"id":{"type":"number","description":"Source ID to delete"}},"required":["id"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"veille_fetch_now","description":"Fetch new content from sources immediately. Optionally specify a single source ID, or omit to fetch from all enabled sources.","parameters":{"type":"object","properties":{"source_id":{"type":"number","description":"Specific source ID to fetch (omit for all)"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"veille_generate_digest","description":"Generate a daily or weekly digest of monitored content. Returns prompt data for the agent LLM to produce the digest text.","parameters":{"type":"object","properties":{"digest_type":{"type":"string","enum":["daily","weekly"],"description":"Type of digest (default: daily)"},"date":{"type":"string","description":"Date for digest (YYYY-MM-DD, defaults to today)"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"veille_transform_content","description":"Transform a digest into a specific content format (blog post, X thread, LinkedIn post, or newsletter). Returns prompt data for the agent LLM to produce the transformed content.","parameters":{"type":"object","properties":{"digest_markdown":{"type":"string","description":"Markdown content of the digest to transform"},"digest_title":{"type":"string","description":"Title of the digest"},"format":{"type":"string","enum":["blog_post","x_thread","linkedin_post","newsletter"],"description":"Target content format"}},"required":["digest_markdown","digest_title","format"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"veille_publish","description":"Publish content to a specific platform (Ghost, WordPress, Twitter, LinkedIn, Dev.to, Telegram, Slack, or Discord)","parameters":{"type":"object","properties":{"content":{"type":"string","description":"Content to publish"},"title":{"type":"string","description":"Content title"},"format":{"type":"string","enum":["blog_post","x_thread","linkedin_post","newsletter"],"description":"Content format"},"platform":{"type":"string","enum":["ghost","wordpress","twitter","linkedin","devto","telegram","slack","discord"],"description":"Target platform"},"digest_id":{"type":"number","description":"Associated digest ID for audit trail"}},"required":["content","title","format","platform"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"veille_search","description":"Search monitored content items by keyword. Returns matching items with titles, URLs, summaries, and metadata.","parameters":{"type":"object","properties":{"query":{"type":"string","description":"Search query"},"limit":{"type":"number","minimum":1,"maximum":100,"description":"Max results (default 20)"}},"required":["query"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"veille_status","description":"Show Lucid Veille system status: source count, item count, latest digests, configured fetchers and publishers, schedule info","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-video', 'Lucid Video', 'Video generation: scene composition, Remotion rendering, asset management', '1.0.0', 'content', '[{"name":"render_video","description":"Render a video from a VideoBrief. Provide template_id, scenes (JSON array), output format, and resolution. Returns a render_id to track progress.","parameters":{"type":"object","properties":{"template_id":{"type":"string","description":"Template ID (e.g. \"social-clip-v1\")"},"scenes":{"type":"string","description":"JSON array of scenes: [{type, duration, props}]"},"format":{"type":"string","enum":["mp4","webm","gif"],"description":"Output format"},"resolution":{"type":"string","enum":["1080p","720p","square","story","reel"],"description":"Output resolution"},"priority":{"type":"string","enum":["burst","standard"],"description":"Rendering priority (burst=Lambda, standard=Railway)"},"brand_colors":{"type":"string","description":"JSON: {primary, secondary, background}"},"data_bindings":{"type":"string","description":"JSON object of data to bind into the template"}},"required":["template_id","scenes","format","resolution"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"list_templates","description":"List available video templates. Optionally filter by category.","parameters":{"type":"object","properties":{"category":{"type":"string","enum":["marketing","data-report","outreach","product","internal"],"description":"Filter by template category"}},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"get_render_status","description":"Check the status and progress of a video render job. Returns status, progress percentage, and video URL when complete.","parameters":{"type":"object","properties":{"render_id":{"type":"string","description":"The render job ID returned by render_video"}},"required":["render_id"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"preview_thumbnail","description":"Generate a thumbnail preview (frame 0) of a video brief without rendering the full video. Fast (<3s). Use to confirm visual before committing to a full render.","parameters":{"type":"object","properties":{"template_id":{"type":"string","description":"Template ID"},"scenes":{"type":"string","description":"JSON array of scenes"},"format":{"type":"string","enum":["mp4","webm","gif"],"description":"Output format"},"resolution":{"type":"string","enum":["1080p","720p","square","story","reel"],"description":"Output resolution"},"brand_colors":{"type":"string","description":"JSON: {primary, secondary, background}"}},"required":["template_id","scenes","format","resolution"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"cancel_render","description":"Cancel a running video render job.","parameters":{"type":"object","properties":{"render_id":{"type":"string","description":"The render job ID to cancel"}},"required":["render_id"],"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-defi', 'Lucid DeFi', 'DeFi operations intelligence: protocol analysis, yield strategies, liquidity management', '4.0.0', 'defi', '[]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
